function sha256(ascii) {
  const mathPow = Math.pow;
  const maxWord = mathPow(2, 32);
  let result = '';
  const words = [];
  const asciiBitLength = ascii.length * 8;
  let hash = [];
  let k = [];
  let primeCounter = 0;
  const isComposite = {};

  for (let candidate = 2; primeCounter < 64; candidate++) {
    if (!isComposite[candidate]) {
      for (let i = 0; i < 313; i += candidate) {
        isComposite[i] = candidate;
      }
      hash[primeCounter] = (mathPow(candidate, 0.5) * maxWord) | 0;
      k[primeCounter++] = (mathPow(candidate, 1 / 3) * maxWord) | 0;
    }
  }

  ascii += '\x80';
  while ((ascii.length % 64) - 56) ascii += '\x00';
  for (let i = 0; i < ascii.length; i++) {
    const j = ascii.charCodeAt(i);
    words[i >> 2] |= j << (((3 - i) % 4) * 8);
  }
  words[words.length] = (asciiBitLength / maxWord) | 0;
  words[words.length] = asciiBitLength;

  for (let j = 0; j < words.length;) {
    const w = words.slice(j, (j += 16));
    const oldHash = hash.slice(0);

    for (let i = 0; i < 64; i++) {
      const w15 = w[i - 15];
      const w2 = w[i - 2];
      const a = hash[0];
      const e = hash[4];
      const temp1 =
        hash[7] +
        (rightRotate(e, 6) ^ rightRotate(e, 11) ^ rightRotate(e, 25)) +
        ((e & hash[5]) ^ (~e & hash[6])) +
        k[i] +
        (w[i] =
          i < 16
            ? w[i]
            : (w[i - 16] +
                (rightRotate(w15, 7) ^ rightRotate(w15, 18) ^ (w15 >>> 3)) +
                w[i - 7] +
                (rightRotate(w2, 17) ^ rightRotate(w2, 19) ^ (w2 >>> 10))) |
              0);
      const temp2 =
        (rightRotate(a, 2) ^ rightRotate(a, 13) ^ rightRotate(a, 22)) +
        ((a & hash[1]) ^ (a & hash[2]) ^ (hash[1] & hash[2]));

      hash = [(temp1 + temp2) | 0].concat(hash);
      hash[4] = (hash[4] + temp1) | 0;
      hash.pop();
    }

    for (let i = 0; i < 8; i++) {
      hash[i] = (hash[i] + oldHash[i]) | 0;
    }
  }

  for (let i = 0; i < 8; i++) {
    for (let j = 3; j + 1; j--) {
      const b = (hash[i] >> (j * 8)) & 255;
      result += ((b < 16 ? '0' : '') + b.toString(16));
    }
  }

  return result;
}

function hexToBinary(hex) {
  let output = '';
  for (let i = 0; i < hex.length; i += 2) {
    output += String.fromCharCode(parseInt(hex.slice(i, i + 2), 16));
  }
  return output;
}

function hmacSha256(key, message) {
  const blockSize = 64;
  let normalizedKey = key;

  if (normalizedKey.length > blockSize) {
    normalizedKey = hexToBinary(sha256(normalizedKey));
  }

  if (normalizedKey.length < blockSize) {
    normalizedKey = normalizedKey.padEnd(blockSize, '\x00');
  }

  let oKeyPad = '';
  let iKeyPad = '';

  for (let i = 0; i < blockSize; i++) {
    const code = normalizedKey.charCodeAt(i);
    oKeyPad += String.fromCharCode(code ^ 0x5c);
    iKeyPad += String.fromCharCode(code ^ 0x36);
  }

  return sha256(oKeyPad + hexToBinary(sha256(iKeyPad + message)));
}

const config = $input.first().json;
const path = '/api/v2/auth/access_token/get';
const timestamp = Math.floor(Date.now() / 1000);
const baseString = `${config.partnerId}${path}${timestamp}${config.shopId}`;
const sign = hmacSha256(config.partnerKey, baseString);

return [
  {
    json: {
      ...config,
      refreshPath: path,
      refreshTimestamp: timestamp,
      refreshSign: sign,
      refreshUrl: `${config.shopeeApiBase}${path}?partner_id=${encodeURIComponent(config.partnerId)}&timestamp=${timestamp}&sign=${sign}&shop_id=${encodeURIComponent(config.shopId)}`,
      refreshBody: {
        refresh_token: config.refreshToken,
        partner_id: Number(config.partnerId),
        shop_id: Number(config.shopId)
      }
    }
  }
];

const refreshResponse = $input.first().json;
const config = $('Workflow Config').first().json;

const refreshed = refreshResponse.response ?? {};
const accessToken = refreshResponse.access_token ?? refreshed.access_token;
const refreshToken = refreshResponse.refresh_token ?? refreshed.refresh_token ?? config.refreshToken;
const expireIn = Number(refreshResponse.expire_in ?? refreshed.expire_in ?? 14400);

if (!accessToken) {
  throw new Error(
    refreshResponse.message ??
      refreshResponse.error ??
      refreshed.message ??
      refreshed.error ??
      'Shopee refresh token response did not include access_token'
  );
}

const tokenExpiry = new Date(Date.now() + expireIn * 1000).toISOString();

return [
  {
    json: {
      ...config,
      accessToken,
      refreshToken,
      tokenExpiry,
      expireIn
    }
  }
];

