const orderListResponse = $input.first().json;
const config = $('Normalize Token Set').first().json;
const orderList = orderListResponse.response?.order_list ?? [];

if (!Array.isArray(orderList) || orderList.length === 0) {
  return [];
}

const orderSnList = orderList.map((order) => order.order_sn).filter(Boolean);
const path = '/api/v2/order/get_order_detail';
const timestamp = Math.floor(Date.now() / 1000);
const baseString = `${config.partnerId}${path}${timestamp}${config.accessToken}${config.shopId}`;
const sign = hmacSha256(config.partnerKey, baseString);
const optionalFields = 'total_amount,shipping_carrier,package_list,create_time,update_time,ship_by_date,shipping_document_info,tracking_no,buyer_username,item_list,recipient_address,order_status,status';
const requestUrl = `${config.shopeeApiBase}${path}?partner_id=${encodeURIComponent(config.partnerId)}&timestamp=${timestamp}&access_token=${encodeURIComponent(config.accessToken)}&shop_id=${encodeURIComponent(config.shopId)}&sign=${sign}&order_sn_list=${encodeURIComponent(orderSnList.join(','))}&response_optional_fields=${encodeURIComponent(optionalFields)}`;

return [
  {
    json: {
      ...config,
      orderSnList,
      detailRequestUrl: requestUrl,
      detailPath: path
    }
  }
];

function unique(values) {
  return [...new Set(values.filter((value) => typeof value === 'string' && value.trim().length > 0))];
}

function extractTrackingCandidates(order) {
  const values = [];

  if (Array.isArray(order.package_list)) {
    for (const pkg of order.package_list) {
      if (pkg?.tracking_number) values.push(pkg.tracking_number);
      if (pkg?.tracking_no) values.push(pkg.tracking_no);
      if (pkg?.package_number) values.push(pkg.package_number);
    }
  }

  if (order.shipping_document_info?.tracking_number) {
    values.push(order.shipping_document_info.tracking_number);
  }

  if (order.shipping_document_info?.tracking_no) {
    values.push(order.shipping_document_info.tracking_no);
  }

  if (order.tracking_no) {
    values.push(order.tracking_no);
  }

  return unique(values);
}

function mapItems(itemList) {
  if (!Array.isArray(itemList)) {
    return [];
  }

  return itemList.map((item) => ({
    item_id: item.item_id ?? null,
    item_name: item.item_name ?? null,
    model_name: item.model_name ?? null,
    model_quantity_purchased: item.model_quantity_purchased ?? null,
    model_sku: item.model_sku ?? null,
    item_sku: item.item_sku ?? null
  }));
}

function normalizePlatformStatus(value) {
  if (typeof value !== 'string' || value.trim().length === 0) {
    return 'unknown';
  }

  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'unknown';
}

const detailResponse = $input.first().json;
const config = $('Normalize Token Set').first().json;
const orders = detailResponse.response?.order_list ?? [];

if (!Array.isArray(orders) || orders.length === 0) {
  return [];
}

return orders.map((order) => {
  const trackingCandidates = extractTrackingCandidates(order);
  const barcodeValue = trackingCandidates[0] ?? order.order_sn;
  const buyerName = order.recipient_address?.name ?? order.buyer_username ?? null;
  const items = mapItems(order.item_list);

  const body = {
    store_id: config.storeId,
    platform_order_id: order.order_sn,
    barcode_value: barcodeValue,
    buyer_name: buyerName,
    platform_status: normalizePlatformStatus(order.order_status ?? order.status),
    items_json: items
  };

  return {
    json: {
      ...body,
      supabaseUrl: config.supabaseUrl,
      serviceRoleKey: config.serviceRoleKey,
      requestUrl: `${config.supabaseUrl}/rest/v1/orders?on_conflict=store_id,platform_order_id`,
      requestBody: JSON.stringify(body)
    }
  };
});
